optimizeDeps: {
  exclude: ["onnxruntime-web"],
  include: ["@ricky0123/vad-web"],
  esbuildOptions: {
    plugins: [
      {
        name: "exclude-onnxruntime",
        setup(build) {
          // Prevent esbuild from trying to bundle onnxruntime-web (WASM-heavy,
          // must be served as-is by the browser)
          build.onResolve({ filter: /^onnxruntime-web/ }, () => ({
            external: true,
          }));
        },
      },
    ],
  },
},
